solutions.javascript:
// Solution
function solve(s) {
  const regex = /FROM\s+(\w+(?=\s+AS|\s+FROM))/g;
  const tableNames = s.match(regex);
  return tableNames.map(tableName => tableName.replace('FROM ', ''))
}
